async function main() {
  const BATCH = 50;
  let total = 0;
  for (let i = 0; i < questions.length; i += BATCH) {
    const batch = questions.slice(i, i + BATCH);
    const r = await rpush(batch);
    total += batch.length;
    console.log(`Pushed batch ${Math.floor(i/BATCH)+1}: ${batch.length} questions → total pushed ${total} | Redis result:`, r?.result ?? r);
  }
  console.log(`\nDone! Pushed ${total} polity questions to ${KEY}`);
}

main().catch(console.error);
